import{c as i,Q as a,j as e,m as t}from"./chunks/framework.CBiVa4O3.js";const u=JSON.parse('{"title":"云服务与互联网基础常识","description":"","frontmatter":{},"headers":[],"relativePath":"../cloudBasicsLearning/目录.md","filePath":"../cloudBasicsLearning/目录.md","lastUpdated":1779015580000}'),s={name:"../cloudBasicsLearning/目录.md"};function o(r,l,n,d,c,h){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="云服务与互联网基础常识" tabindex="-1">云服务与互联网基础常识 <a class="header-anchor" href="#云服务与互联网基础常识" aria-label="Permalink to &quot;云服务与互联网基础常识&quot;">​</a></h1><h2 id="系列定位" tabindex="-1">系列定位 <a class="header-anchor" href="#系列定位" aria-label="Permalink to &quot;系列定位&quot;">​</a></h2><p>这是一套面向网站、App、SaaS、独立开发和云部署的基础常识目录。</p><p>它回答的问题不是“某个按钮在哪里”,而是:</p><ul><li>一个云服务免费套餐到底在限制什么</li><li>DNS、CDN、SSL、WAF、DDoS、SLA 这些词分别处在哪一层</li><li>Serverless、对象存储、托管数据库为什么便宜,又有什么边界</li><li>如何看懂请求数、流量、存储、构建分钟、日志保留、超额计费</li><li>小团队该怎么用云服务,避免一开始就过度设计或账单失控</li></ul><h2 id="大纲目录" tabindex="-1">大纲目录 <a class="header-anchor" href="#大纲目录" aria-label="Permalink to &quot;大纲目录&quot;">​</a></h2><h3 id="第一层-互联网入口与访问链路" tabindex="-1">第一层:互联网入口与访问链路 <a class="header-anchor" href="#第一层-互联网入口与访问链路" aria-label="Permalink to &quot;第一层:互联网入口与访问链路&quot;">​</a></h3><ol><li>云服务与互联网基础常识总览</li><li>域名是什么:注册商、注册局、DNS 托管的区别</li><li>DNS 解析:记录类型、TTL、权威 DNS、递归 DNS</li><li>IP、端口与 HTTP:用户访问网站时发生了什么</li><li>HTTPS 与证书:SSL/TLS、CA、自动续期、证书错误</li><li>CDN 是什么:缓存、边缘节点、回源、命中率</li><li>反向代理与网关:Nginx、Cloudflare、API Gateway 的位置</li><li>WAF 与 DDoS 防护:它们能挡什么,挡不了什么</li></ol><h3 id="第二层-云资源与部署模型" tabindex="-1">第二层:云资源与部署模型 <a class="header-anchor" href="#第二层-云资源与部署模型" aria-label="Permalink to &quot;第二层:云资源与部署模型&quot;">​</a></h3><ol start="9"><li>云服务器是什么:CPU、内存、磁盘、带宽、地域</li><li>共享主机、VPS、云服务器、裸金属的区别</li><li>容器与镜像:为什么部署不只是上传代码</li><li>Kubernetes 是什么:适合谁,不适合谁</li><li>Serverless 是什么:函数、冷启动、触发器、限制</li><li>静态托管与前端部署:Pages、Vercel、Netlify、OSS 静态站</li><li>对象存储:Bucket、Object、S3、R2、OSS、生命周期</li><li>数据库服务:托管数据库、读写额度、连接数、备份</li><li>队列、缓存与消息:Redis、MQ、异步任务的常识</li></ol><h3 id="第三层-稳定性、可观测性与恢复" tabindex="-1">第三层:稳定性、可观测性与恢复 <a class="header-anchor" href="#第三层-稳定性、可观测性与恢复" aria-label="Permalink to &quot;第三层:稳定性、可观测性与恢复&quot;">​</a></h3><ol start="18"><li>SLA / SLO / SLI:服务承诺、内部目标、真实指标</li><li>Uptime 与 Downtime:99%、99.9%、99.99% 到底差多少</li><li>延迟、吞吐量与并发:性能指标怎么读</li><li>监控是什么:指标、日志、链路追踪的分工</li><li>告警是什么:阈值、误报、漏报、升级路径</li><li>日志保留与审计:为什么免费套餐常限制日志时间</li><li>备份、快照与恢复:备份不是有文件就行</li><li>容灾与多地域:高可用、故障切换、成本边界</li></ol><h3 id="第四层-安全、身份与权限" tabindex="-1">第四层:安全、身份与权限 <a class="header-anchor" href="#第四层-安全、身份与权限" aria-label="Permalink to &quot;第四层:安全、身份与权限&quot;">​</a></h3><ol start="26"><li>账号安全:Root 账号、MFA、子账号、最小权限</li><li>IAM 是什么:用户、角色、策略、临时凭证</li><li>API Key、Token 与 Secret:怎么存、怎么轮换、怎么泄露</li><li>OAuth、OIDC 与 SSO:登录不是自己存密码这么简单</li><li>CORS、Cookie 与跨域:前后端联调最常见的安全边界</li><li>防刷与 Bot 管理:验证码、限流、风控、误杀</li><li>合规与数据位置:隐私政策、数据跨境、日志敏感信息</li><li>安全责任共担模型:云厂商负责什么,你负责什么</li></ol><h3 id="第五层-计费、免费套餐与选型" tabindex="-1">第五层:计费、免费套餐与选型 <a class="header-anchor" href="#第五层-计费、免费套餐与选型" aria-label="Permalink to &quot;第五层:计费、免费套餐与选型&quot;">​</a></h3><ol start="34"><li>云服务计费模型:按量、包年包月、预留、阶梯价</li><li>免费额度怎么看:请求数、存储量、出站流量、构建分钟</li><li>带宽与流量费:为什么出口流量最容易超预算</li><li>请求数与操作数:API 调用、Class A/B、读写次数</li><li>构建次数与运行时间:CI/CD、Pages、Serverless 的隐形限制</li><li>账单与预算告警:小项目也要设置成本护栏</li><li>Cloudflare 免费套餐拆解:适合什么,不适合什么</li><li>Vercel / Netlify / Firebase / Supabase 免费套餐怎么看</li><li>小团队云服务选型:从 0 到 1 的保守架构</li></ol><h2 id="最小阅读路径" tabindex="-1">最小阅读路径 <a class="header-anchor" href="#最小阅读路径" aria-label="Permalink to &quot;最小阅读路径&quot;">​</a></h2><p>只想看懂 Cloudflare、Vercel 这类免费套餐:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 -&gt; 02 -&gt; 03 -&gt; 05 -&gt; 06 -&gt; 14 -&gt; 18 -&gt; 34 -&gt; 35 -&gt; 40 -&gt; 41</span></span></code></pre></div><p>想从零部署一个可靠的小网站:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01 -&gt; 02 -&gt; 03 -&gt; 05 -&gt; 06 -&gt; 14 -&gt; 15 -&gt; 21 -&gt; 22 -&gt; 24 -&gt; 26 -&gt; 28 -&gt; 34 -&gt; 39 -&gt; 42</span></span></code></pre></div><p>想系统补齐云服务常识:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>按 01-42 顺序读,读完每一层后找一个真实云服务套餐页做拆解。</span></span></code></pre></div>',23)])])}const g=i(s,[["render",o]]);export{u as __pageData,g as default};
